previewCss:
.darma-loader-darma-custom-528 {color: var(--loader-color, #6d28d9);
  --loader-secondary-color: var(--loader-secondary-color, #f0abfc);
  --loader-bg: var(--loader-bg, #ffffff);
   height: 60px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-528:before, .darma-loader-darma-custom-528:after  {
  content: "";
   background: radial-gradient(farthest-side,currentColor 15%,#0000 18%)0 0/50% 100%, radial-gradient(50% 100% at 50% 160%,currentColor 95%,#0000) 0 0 /50% 50%, radial-gradient(50% 100% at 50% -60%,currentColor 95%,#0000) 0 100%/50% 50%;
   background-repeat: repeat-x;
   -webkit-mask: radial-gradient(50% 100%,currentColor 95%,#0000) 0 100%/50% 0% repeat-x;
   animation: darma-loader-darma-custom-528-l4 1s infinite alternate ease-in;
}
.darma-loader-darma-custom-528:after  {
  animation-duration: .7s;
}
@keyframes darma-loader-darma-custom-528-l4  {
  0%, 70% {-webkit-mask-size:50% 100%}
85% {-webkit-mask-size:50% 0}
100% {-webkit-mask-size:50% 100%}
}

